def parse_concentration(value_str):
    """Parse concentration like '5.0 mM' or '100 uM'"""
    parts = value_str.split()
    value = float(parts[0])
    unit = parts[1]

    if unit == 'mM':
        return value * 1e-3
    if unit == 'uM':
        return value * 1e-6
    return value
